#include <stdio.h>
#include <stdlib.h>

// Define structure for RGB pixel
typedef struct {
 int R, G, B;
} Pixel;

// Function to apply unsharp masking
void unsharpMasking(Pixel *img, int width, int height, float k) {
 // Compute blurred image
 Pixel *blurred = (Pixel *)malloc(width * height * sizeof(Pixel));
 for (int i = 1; i < width - 1; i++) {
 for (int j = 1; j < height - 1; j++) {
 int idx = j * width + i;
 blurred[idx].R = (img[idx].R + img[idx - 1].R + img[idx + 1].R + img[idx - width].R + img[idx + width].R) / 5;
 blurred[idx].G = (img[idx].G + img[idx - 1].G + img[idx + 1].G + img[idx - width].G + img[idx + width].G) / 5;
 blurred[idx].B = (img[idx].B + img[idx - 1].B + img[idx + 1].B + img[idx - width].B + img[idx + width].B) / 5;
 }
 }

 // Apply unsharp masking
 for (int i = 0; i < width; i++) {
 for (int j = 0; j < height; j++) {
 int idx = j * width + i;
 img[idx].R = img[idx].R + k * (img[idx].R - blurred[idx].R);
 img[idx].G = img[idx].G + k * (img[idx].G - blurred[idx].G);
 img[idx].B = img[idx].B + k * (img[idx].B - blurred[idx].B);
 }
 }

 free(blurred);
}

int main() {
 // Load RGB image
 int width, height;
 Pixel *img = (Pixel *)malloc(width * height * sizeof(Pixel));

 // Apply unsharp masking
 unsharpMasking(img, width, height, 0.5);

 // Save sharpened image
 return 0;
}
